const express = require('express');
const axios = require('axios');
const jwt = require('jsonwebtoken');

const app = express();

app.use(express.urlencoded({ extended: true }));
app.use(express.json());

const conf = {
  issuer: 'https://your-issuer.com',
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret',
};

let tokens;

app.get('/login', (req, res) => {
  const authUrl = `https://your-issuer.com/auth?response_type=code&client_id=${conf.clientId}&redirect_uri=http://localhost:3000/callback`;
  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  try {
    const code = req.query.code;
    tokens = await exchangeCodeForTokens(code);
    if (!tokens.id_token) {
      return res.status(401).send({ message: 'Authentication failed' });
    }
    const decoded = jwt.decode(tokens.id_token, { complete: true });
    createSession(decoded.payload);
    res.redirect('/');
  } catch (error) {
    console.error(error);
    res.status(500).send({ message: 'Internal server error' });
  }
});

async function exchangeCodeForTokens(code) {
  const authUrl = `${conf.issuer}/token`;
  const tokenResponse = await axios.post(authUrl, buildTokenRequest(code), { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } });
  return tokenResponse.data;
}

function buildTokenRequest(code) {
  return new URLSearchParams({
    grant_type: 'authorization_code',
    code,
    redirect_uri: 'http://localhost:3000/callback',
    client_id: conf.clientId,
    client_secret: conf.clientSecret,
  }).toString();
}

